#!/usr/bin/env python3

import sys
import argparse
import json
from kafka.admin import KafkaAdminClient, NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import KafkaError, TopicAlreadyExistsError, UnknownTopicOrPartitionError


def create_admin_client(bootstrap_servers):
    return KafkaAdminClient(
        bootstrap_servers=bootstrap_servers,
        client_id='kafka-admin-cli'
    )


def create_topics(admin_client, topics_config):
    new_topics = []
    for topic_conf in topics_config:
        topic_name = topic_conf['name']
        num_partitions = topic_conf.get('partitions', 1)
        replication_factor = topic_conf.get('replication_factor', 1)
        topic_configs = topic_conf.get('config', {})
        
        new_topic = NewTopic(
            name=topic_name,
            num_partitions=num_partitions,
            replication_factor=replication_factor,
            topic_configs=topic_configs
        )
        new_topics.append(new_topic)
    
    try:
        result = admin_client.create_topics(new_topics=new_topics, validate_only=False)
        for topic, future in result.items():
            try:
                future.result()
                print(f"Topic '{topic}' created successfully")
            except TopicAlreadyExistsError:
                print(f"Topic '{topic}' already exists")
            except Exception as e:
                print(f"Failed to create topic '{topic}': {e}")
    except Exception as e:
        print(f"Error creating topics: {e}")


def delete_topics(admin_client, topic_names):
    try:
        result = admin_client.delete_topics(topics=topic_names)
        for topic, future in result.items():
            try:
                future.result()
                print(f"Topic '{topic}' deleted successfully")
            except UnknownTopicOrPartitionError:
                print(f"Topic '{topic}' does not exist")
            except Exception as e:
                print(f"Failed to delete topic '{topic}': {e}")
    except Exception as e:
        print(f"Error deleting topics: {e}")


def list_topics(admin_client):
    try:
        topics = admin_client.list_topics()
        print("Available topics:")
        for topic in sorted(topics):
            print(f"  - {topic}")
        return topics
    except Exception as e:
        print(f"Error listing topics: {e}")
        return []


def describe_topics(admin_client, topic_names):
    try:
        consumer_client = admin_client._client
        metadata = consumer_client.cluster
        
        for topic_name in topic_names:
            if topic_name not in metadata.topics():
                print(f"Topic '{topic_name}' not found")
                continue
                
            topic_metadata = metadata.topics()[topic_name]
            print(f"\nTopic: {topic_name}")
            print(f"Partitions: {len(topic_metadata)}")
            
            for partition_id, partition_metadata in topic_metadata.items():
                print(f"  Partition {partition_id}:")
                print(f"    Leader: {partition_metadata.leader}")
                print(f"    Replicas: {partition_metadata.replicas}")
                print(f"    ISR: {partition_metadata.isr}")
    except Exception as e:
        print(f"Error describing topics: {e}")


def alter_topic_config(admin_client, topic_name, configs):
    try:
        config_resource = ConfigResource(
            ConfigResourceType.TOPIC,
            topic_name,
            configs=configs
        )
        
        result = admin_client.alter_configs([config_resource])
        for resource, future in result.items():
            try:
                future.result()
                print(f"Configuration for topic '{topic_name}' updated successfully")
            except Exception as e:
                print(f"Failed to update configuration for topic '{topic_name}': {e}")
    except Exception as e:
        print(f"Error altering topic configuration: {e}")


def describe_topic_config(admin_client, topic_names):
    try:
        config_resources = [
            ConfigResource(ConfigResourceType.TOPIC, topic_name)
            for topic_name in topic_names
        ]
        
        result = admin_client.describe_configs(config_resources)
        
        for resource, future in result.items():
            try:
                config = future.result()
                print(f"\nTopic: {resource.name}")
                print("Configuration:")
                for key, value in config.items():
                    print(f"  {key}: {value.value}")
            except Exception as e:
                print(f"Failed to describe configuration for topic '{resource.name}': {e}")
    except Exception as e:
        print(f"Error describing topic configuration: {e}")


def create_partitions(admin_client, topic_partitions):
    try:
        from kafka.admin import NewPartitions
        
        new_partitions = {}
        for topic, count in topic_partitions.items():
            new_partitions[topic] = NewPartitions(total_count=count)
        
        result = admin_client.create_partitions(new_partitions)
        
        for topic, future in result.items():
            try:
                future.result()
                print(f"Partitions for topic '{topic}' created successfully")
            except Exception as e:
                print(f"Failed to create partitions for topic '{topic}': {e}")
    except Exception as e:
        print(f"Error creating partitions: {e}")


def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration Tool')
    parser.add_argument('--bootstrap-servers', '-b', required=True,
                        help='Kafka bootstrap servers (comma-separated)')
    
    subparsers = parser.add_subparsers(dest='command', help='Command to execute')
    
    create_parser = subparsers.add_parser('create', help='Create topics')
    create_parser.add_argument('--topics', '-t', required=True,
                               help='Topics configuration (JSON format)')
    create_parser.add_argument('--file', '-f',
                               help='Path to JSON file with topics configuration')
    
    delete_parser = subparsers.add_parser('delete', help='Delete topics')
    delete_parser.add_argument('topics', nargs='+', help='Topic names to delete')
    
    list_parser = subparsers.add_parser('list', help='List all topics')
    
    describe_parser = subparsers.add_parser('describe', help='Describe topics')
    describe_parser.add_argument('topics', nargs='+', help='Topic names to describe')
    
    config_parser = subparsers.add_parser('config', help='Manage topic configuration')
    config_subparsers = config_parser.add_subparsers(dest='config_command')
    
    set_config_parser = config_subparsers.add_parser('set', help='Set topic configuration')
    set_config_parser.add_argument('--topic', '-t', required=True, help='Topic name')
    set_config_parser.add_argument('--configs', '-c', required=True,
                                    help='Configuration key-value pairs (JSON format)')
    
    get_config_parser = config_subparsers.add_parser('get', help='Get topic configuration')
    get_config_parser.add_argument('topics', nargs='+', help='Topic names')
    
    partitions_parser = subparsers.add_parser('add-partitions', help='Add partitions to topics')
    partitions_parser.add_argument('--topic', '-t', required=True, help='Topic name')
    partitions_parser.add_argument('--partitions', '-p', required=True, type=int,
                                    help='Total number of partitions')
    
    args = parser.parse_args()
    
    if not args.command:
        parser.print_help()
        sys.exit(1)
    
    bootstrap_servers = args.bootstrap_servers.split(',')
    admin_client = create_admin_client(bootstrap_servers)
    
    try:
        if args.command == 'create':
            if args.file:
                with open(args.file, 'r') as f:
                    topics_config = json.load(f)
            else:
                topics_config = json.loads(args.topics)
            
            if not isinstance(topics_config, list):
                topics_config = [topics_config]
            
            create_topics(admin_client, topics_config)
        
        elif args.command == 'delete':
            delete_topics(admin_client, args.topics)
        
        elif args.command == 'list':
            list_topics(admin_client)
        
        elif args.command == 'describe':
            describe_topics(admin_client, args.topics)
        
        elif args.command == 'config':
            if args.config_command == 'set':
                configs = json.loads(args.configs)
                alter_topic_config(admin_client, args.topic, configs)
            
            elif args.config_command == 'get':
                describe_topic_config(admin_client, args.topics)
            
            else:
                config_parser.print_help()
        
        elif args.command == 'add-partitions':
            topic_partitions = {args.topic: args.partitions}
            create_partitions(admin_client, topic_partitions)
    
    finally:
        admin_client.close()


if __name__ == '__main__':
    main()